import { getUserMembership } from "../features/users/membership.js";

export const renderHomePage = async (user) => {
    const page = document.getElementById('home-page');
    if (!page) return;

    const membershipColor = { Bronze: '#cd7f32', Silver: '#aaa', Gold: '#d4af37' };

    page.innerHTML = `
        <div class="home-hero">
            <img src="assets/logo/logo.png" alt="Alisya Beauty" class="home-logo" onerror="this.style.display='none'">
            <h1 class="home-title">Alisya Beauty</h1>
            <p class="home-subtitle">Premium Muslimah Salon</p>
        </div>

        <div class="home-profile-card">
            <img src="${user.photoURL || 'assets/logo/default-avatar.png'}" alt="Avatar" class="home-avatar">
            <div>
                <div class="home-welcome">Halo, <strong>${user.displayName?.split(' ')[0] || 'Kamu'}</strong> 👋</div>
                <div id="membership-badge" class="membership-badge">Memuat membership...</div>
            </div>
        </div>

        <div class="home-menu-grid">
            <button class="home-menu-btn" data-page="booking">
                <i class="fa-solid fa-calendar-check"></i>
                <span>Booking</span>
            </button>
            <button class="home-menu-btn" data-page="services">
                <i class="fa-solid fa-spa"></i>
                <span>Layanan</span>
            </button>
            <button class="home-menu-btn" data-page="shop">
                <i class="fa-solid fa-cart-shopping"></i>
                <span>Produk</span>
            </button>
            <button class="home-menu-btn" data-page="gallery">
                <i class="fa-solid fa-images"></i>
                <span>Gallery</span>
            </button>
        </div>

        <div class="home-info-section">
            <h3><i class="fa-solid fa-circle-info"></i> Tentang Kami</h3>
            <p>Alisya Beauty adalah salon muslimah premium yang memberikan layanan perawatan terbaik dengan standar kenyamanan dan privasi tinggi.</p>
            <div class="home-contact-links">
                <a href="https://wa.me/" target="_blank" class="contact-btn whatsapp">
                    <i class="fa-brands fa-whatsapp"></i> WhatsApp
                </a>
                <a href="https://instagram.com/" target="_blank" class="contact-btn instagram">
                    <i class="fa-brands fa-instagram"></i> Instagram
                </a>
            </div>
        </div>
    `;

    page.querySelectorAll('.home-menu-btn').forEach(btn => {
        btn.addEventListener('click', () => {
            const target = btn.dataset.page;
            document.querySelectorAll('.nav-link').forEach(nl => nl.classList.remove('active'));
            document.querySelector(`.nav-link[data-page="${target}"]`)?.classList.add('active');
            document.querySelectorAll('.spa-page').forEach(p => { p.style.display = 'none'; p.classList.remove('active'); });
            const targetPage = document.getElementById(target + '-page');
            if (targetPage) { targetPage.style.display = 'block'; targetPage.classList.add('active'); }
        });
    });

    try {
        const membership = await getUserMembership(user.uid);
        const badge = document.getElementById('membership-badge');
        if (badge && membership) {
            const level = membership.level || 'Bronze';
            const color = membershipColor[level] || '#cd7f32';
            badge.innerHTML = `<i class="fa-solid fa-crown" style="color:${color}"></i> <span style="color:${color}">${level}</span> · ${membership.points || 0} poin`;
        } else if (badge) {
            badge.textContent = '🥉 Bronze · 0 poin';
        }
    } catch {
        const badge = document.getElementById('membership-badge');
        if (badge) badge.textContent = '🥉 Bronze · 0 poin';
    }
};

import { getTreatments } from "../features/admin/treatmentManager.js";

export const renderServicesPage = async () => {
    const page = document.getElementById('services-page');
    if (!page) return;

    page.innerHTML = `
        <div class="page-container">
            <h2 class="page-title"><i class="fa-solid fa-spa"></i> Layanan Kami</h2>
            <div id="treatments-list"><div class="page-loading"><div class="spinner-sm"></div> Memuat layanan...</div></div>
        </div>
    `;

    const container = document.getElementById('treatments-list');
    try {
        const treatments = await getTreatments();
        if (!treatments.length) {
            container.innerHTML = '<p class="page-empty">Belum ada layanan tersedia.</p>';
            return;
        }
        container.innerHTML = treatments.map(t => `
            <div class="treatment-item">
                <div class="treatment-item-header" data-id="${t.id}">
                    <div class="treatment-item-name">
                        <i class="fa-solid fa-leaf"></i>
                        <span>${t.name}</span>
                    </div>
                    <div class="treatment-item-right">
                        <span class="treatment-price">Rp ${Number(t.price || 0).toLocaleString('id-ID')}</span>
                        <i class="fa-solid fa-chevron-down chevron-icon"></i>
                    </div>
                </div>
                <div class="treatment-item-body" id="body-${t.id}" style="display:none;">
                    <p>${t.description || 'Layanan perawatan premium untuk muslimah.'}</p>
                    ${t.duration ? `<p><i class="fa-regular fa-clock"></i> Durasi: <strong>${t.duration} menit</strong></p>` : ''}
                    <button class="btn-book-now" data-name="${t.name}" data-id="${t.id}">
                        <i class="fa-solid fa-calendar-plus"></i> Booking Sekarang
                    </button>
                </div>
            </div>
        `).join('');

        container.querySelectorAll('.treatment-item-header').forEach(header => {
            header.addEventListener('click', () => {
                const id = header.dataset.id;
                const body = document.getElementById('body-' + id);
                const chevron = header.querySelector('.chevron-icon');
                const isOpen = body.style.display === 'block';
                body.style.display = isOpen ? 'none' : 'block';
                chevron.style.transform = isOpen ? 'rotate(0deg)' : 'rotate(180deg)';
            });
        });

        container.querySelectorAll('.btn-book-now').forEach(btn => {
            btn.addEventListener('click', () => {
                document.querySelectorAll('.spa-page').forEach(p => { p.style.display = 'none'; p.classList.remove('active'); });
                const bookingPage = document.getElementById('booking-page');
                if (bookingPage) { bookingPage.style.display = 'block'; bookingPage.classList.add('active'); }
                const select = document.getElementById('booking-treatment');
                if (select) select.value = btn.dataset.name;
                document.querySelectorAll('.nav-link').forEach(nl => nl.classList.remove('active'));
                document.querySelector('.nav-link[data-page="booking"]')?.classList.add('active');
            });
        });
    } catch {
        container.innerHTML = '<p class="page-empty">Gagal memuat layanan. Coba lagi nanti.</p>';
    }
};

import { getProducts } from "../features/admin/productManager.js";

export const renderShopPage = async () => {
    const page = document.getElementById('shop-page');
    if (!page) return;

    page.innerHTML = `
        <div class="page-container">
            <h2 class="page-title"><i class="fa-solid fa-cart-shopping"></i> Produk</h2>
            <div id="products-grid" class="products-grid"><div class="page-loading"><div class="spinner-sm"></div> Memuat produk...</div></div>
        </div>
    `;

    const container = document.getElementById('products-grid');
    try {
        const products = await getProducts();
        if (!products.length) {
            container.innerHTML = '<p class="page-empty" style="grid-column:1/-1">Belum ada produk tersedia.</p>';
            return;
        }
        container.innerHTML = products.map(p => `
            <div class="product-card">
                <div class="product-img-wrapper">
                    <img src="${p.imageUrl || ''}" alt="${p.name}" onerror="this.parentElement.innerHTML='<div class=\\'product-img-placeholder\\'><i class=\\"fa-solid fa-box-open\\"></i></div>'">
                </div>
                <div class="product-info">
                    <h3>${p.name}</h3>
                    ${p.description ? `<p class="product-desc">${p.description}</p>` : ''}
                    <p class="product-price">Rp ${Number(p.price || 0).toLocaleString('id-ID')}</p>
                </div>
            </div>
        `).join('');
    } catch {
        container.innerHTML = '<p class="page-empty" style="grid-column:1/-1">Gagal memuat produk.</p>';
    }
};

import { auth, db } from "../config/firebase.js";
import { collection, addDoc } from "https://www.gstatic.com/firebasejs/10.7.1/firebase-firestore.js";
import { getTreatments } from "../features/admin/treatmentManager.js";
import { showToast } from "../components/toast.js";

export const renderBookingPage = async () => {
    const page = document.getElementById('booking-page');
    if (!page) return;

    let treatments = [];
    try { treatments = await getTreatments(); } catch {}

    const treatmentOptions = treatments.length
        ? treatments.map(t => `<option value="${t.name}">${t.name} — Rp ${Number(t.price || 0).toLocaleString('id-ID')}</option>`).join('')
        : '<option value="">Belum ada layanan</option>';

    const today = new Date().toISOString().split('T')[0];

    page.innerHTML = `
        <div class="page-container">
            <h2 class="page-title"><i class="fa-solid fa-calendar-check"></i> Booking</h2>
            <div id="booking-list-section">
                <h3 class="section-subtitle">Booking Saya</h3>
                <div id="my-bookings"><div class="page-loading"><div class="spinner-sm"></div></div></div>
            </div>
            <div class="booking-form-card">
                <h3 class="section-subtitle">Buat Booking Baru</h3>
                <form id="booking-form">
                    <div class="form-group">
                        <label>Layanan</label>
                        <select id="booking-treatment" required>
                            <option value="">-- Pilih Layanan --</option>
                            ${treatmentOptions}
                        </select>
                    </div>
                    <div class="form-group">
                        <label>Tanggal</label>
                        <input type="date" id="booking-date" min="${today}" required>
                    </div>
                    <div class="form-group">
                        <label>Waktu</label>
                        <select id="booking-time" required>
                            <option value="">-- Pilih Waktu --</option>
                            <option>08:00</option><option>09:00</option><option>10:00</option>
                            <option>11:00</option><option>13:00</option><option>14:00</option>
                            <option>15:00</option><option>16:00</option>
                        </select>
                    </div>
                    <div class="form-group">
                        <label>Catatan (opsional)</label>
                        <textarea id="booking-notes" rows="3" placeholder="Tulis catatan khusus..."></textarea>
                    </div>
                    <button type="submit" class="btn-submit" id="btn-submit-booking">
                        <i class="fa-solid fa-paper-plane"></i> Kirim Booking
                    </button>
                </form>
            </div>
        </div>
    `;

    loadMyBookings();

    document.getElementById('booking-form').addEventListener('submit', async (e) => {
        e.preventDefault();
        const user = auth.currentUser;
        if (!user) return;

        const btn = document.getElementById('btn-submit-booking');
        btn.disabled = true;
        btn.innerHTML = '<i class="fa-solid fa-spinner fa-spin"></i> Memproses...';

        const treatment = document.getElementById('booking-treatment').value;
        const date = document.getElementById('booking-date').value;
        const time = document.getElementById('booking-time').value;
        const notes = document.getElementById('booking-notes').value;

        try {
            await addDoc(collection(db, 'bookings'), {
                userId: user.uid,
                userName: user.displayName,
                userEmail: user.email,
                treatment, date, time, notes,
                status: 'pending',
                createdAt: new Date()
            });
            showToast('✅ Booking berhasil dikirim!');
            document.getElementById('booking-form').reset();
            loadMyBookings();
        } catch (err) {
            showToast('❌ Gagal booking. Coba lagi.');
            console.error(err);
        } finally {
            btn.disabled = false;
            btn.innerHTML = '<i class="fa-solid fa-paper-plane"></i> Kirim Booking';
        }
    });
};

const loadMyBookings = async () => {
    const container = document.getElementById('my-bookings');
    if (!container) return;
    const user = auth.currentUser;
    if (!user) return;

    const { getDocs, query, where, orderBy } = await import("https://www.gstatic.com/firebasejs/10.7.1/firebase-firestore.js");
    const { collection: col } = await import("https://www.gstatic.com/firebasejs/10.7.1/firebase-firestore.js");

    try {
        const q = query(col(db, 'bookings'), where('userId', '==', user.uid), orderBy('createdAt', 'desc'));
        const snap = await getDocs(q);
        if (snap.empty) {
            container.innerHTML = '<p class="page-empty">Belum ada booking.</p>';
            return;
        }
        const statusColor = { pending: '#f0a500', confirmed: '#4caf50', done: '#aaa', cancelled: '#f44336' };
        container.innerHTML = snap.docs.map(d => {
            const b = d.data();
            const color = statusColor[b.status] || '#aaa';
            return `
                <div class="booking-card">
                    <div class="booking-card-info">
                        <strong>${b.treatment}</strong>
                        <span>${b.date} · ${b.time}</span>
                        ${b.notes ? `<span style="opacity:0.6">${b.notes}</span>` : ''}
                    </div>
                    <span class="booking-status" style="color:${color};border-color:${color}">${b.status}</span>
                </div>
            `;
        }).join('');
    } catch {
        container.innerHTML = '<p class="page-empty">Gagal memuat booking.</p>';
    }
};

export const renderGalleryPage = () => {
    const page = document.getElementById('gallery-page');
    if (!page) return;

    page.innerHTML = `
        <div class="page-container">
            <h2 class="page-title"><i class="fa-solid fa-images"></i> Gallery</h2>
            <div class="gallery-grid">
                ${Array.from({length: 6}, (_, i) => `
                    <div class="gallery-item">
                        <div class="gallery-placeholder">
                            <i class="fa-solid fa-image"></i>
                            <span>Foto ${i + 1}</span>
                        </div>
                    </div>
                `).join('')}
            </div>
            <p class="gallery-note">
                <i class="fa-brands fa-instagram"></i> 
                Follow Instagram kami untuk melihat foto & promo terbaru!
            </p>
        </div>
    `;
};

import { auth } from "../../config/firebase.js";
import {
    signInWithPopup,
    GoogleAuthProvider,
    onAuthStateChanged,
    signOut
} from "https://www.gstatic.com/firebasejs/10.7.1/firebase-auth.js";
import { initAdminDashboard } from "../admin/adminDashboard.js";
import { renderHomePage } from "../../pages/homePage.js";
import { renderServicesPage } from "../../pages/servicesPage.js";
import { renderShopPage } from "../../pages/shopPage.js";
import { renderBookingPage } from "../../pages/bookingPage.js";
import { renderGalleryPage } from "../../pages/galleryPage.js";

const provider = new GoogleAuthProvider();

const initPages = async (user) => {
    await renderHomePage(user);
    renderGalleryPage();
    renderServicesPage();
    renderShopPage();
    renderBookingPage();
};

export const initializeAuth = () => {
    const loginBtn = document.getElementById('btnLogin');
    if (loginBtn) {
        loginBtn.addEventListener('click', async () => {
            try {
                await signInWithPopup(auth, provider);
            } catch (error) {
                console.error("Error Login:", error.code, error.message);
                alert("Gagal login: " + error.code);
            }
        });
    }

    const logoutBtn = document.getElementById('logout-btn');
    if (logoutBtn) {
        logoutBtn.addEventListener('click', async (e) => {
            e.preventDefault();
            try {
                await signOut(auth);
                window.location.reload();
            } catch (error) {
                console.error("Gagal logout:", error);
            }
        });
    }

    onAuthStateChanged(auth, async (user) => {
        const loadingScreen = document.getElementById('loading-screen');
        if (loadingScreen) loadingScreen.style.display = 'none';

        const loginOverlay = document.getElementById('login-overlay');
        const appContainer = document.getElementById('app-container');
        const navbar = document.querySelector('.navbar');
        const bottomNav = document.getElementById('bottom-nav');
        const sidebar = document.getElementById('sidebar');

        if (user) {
            if (loginOverlay) loginOverlay.classList.add('hidden');
            if (appContainer) appContainer.classList.remove('hidden');
            if (navbar) navbar.classList.remove('hidden');
            if (bottomNav) bottomNav.classList.remove('hidden');
            if (sidebar) sidebar.classList.remove('hidden');

            const userAvatar = document.getElementById('user-avatar');
            const userName = document.getElementById('user-name');
            const userEmail = document.getElementById('user-email');
            if (userAvatar) userAvatar.src = user.photoURL || 'assets/logo/default-avatar.png';
            if (userName) userName.textContent = user.displayName || 'User';
            if (userEmail) userEmail.textContent = user.email;

            await initPages(user);
            initAdminDashboard(user);
        } else {
            if (loginOverlay) loginOverlay.classList.remove('hidden');
            if (appContainer) appContainer.classList.add('hidden');
            if (navbar) navbar.classList.add('hidden');
            if (bottomNav) bottomNav.classList.add('hidden');
        }
    });
};

export const navigateTo = (pageId) => {
    document.querySelectorAll('.spa-page').forEach(page => {
        page.style.display = 'none';
        page.classList.remove('active');
    });
    const targetPage = document.getElementById(pageId);
    if (targetPage) {
        targetPage.style.display = 'block';
        targetPage.classList.add('active');
        window.history.pushState({ page: pageId }, '', `#${pageId}`);
    }
};

export const initRouter = () => {
    document.querySelectorAll('.nav-link').forEach(link => {
        link.addEventListener('click', (e) => {
            e.preventDefault();
            const target = link.getAttribute('data-page');
            document.querySelectorAll('.nav-link').forEach(l => l.classList.remove('active'));
            link.classList.add('active');
            navigateTo(target + '-page');
        });
    });

    window.addEventListener('popstate', (e) => {
        if (e.state?.page) navigateTo(e.state.page);
    });
};

