.page-loading { display: flex; align-items: center; gap: 10px; color: #666; padding: 30px 0; justify-content: center; font-size: 0.9rem; }
.page-empty { color: #555; text-align: center; padding: 40px 0; font-size: 0.9rem; }
.spinner-sm { width: 20px; height: 20px; border: 2px solid rgba(255,255,255,.1); border-top-color: var(--gold); border-radius: 50%; animation: spin .8s linear infinite; }

/* --- HOME PAGE --- */
.home-hero { text-align: center; padding: 30px 20px 20px; }
.home-logo { width: 90px; height: 90px; object-fit: contain; border-radius: 50%; margin-bottom: 12px; }
.home-title { font-size: 1.8rem; font-weight: 800; color: var(--gold); letter-spacing: 2px; }
.home-subtitle { color: #888; font-size: 0.85rem; margin-top: 4px; }
.home-profile-card { margin: 0 16px 20px; background: var(--bg-card); border: 1px solid #2a2a2a; border-radius: 16px; padding: 16px 18px; display: flex; align-items: center; gap: 14px; }
.home-avatar { width: 52px; height: 52px; border-radius: 50%; object-fit: cover; border: 2px solid var(--gold); }
.home-welcome { font-size: 1rem; color: var(--text-light); }
.membership-badge { font-size: 0.8rem; color: #aaa; margin-top: 4px; display: flex; align-items: center; gap: 6px; }
.home-menu-grid { display: grid; grid-template-columns: 1fr 1fr; gap: 12px; padding: 0 16px 20px; }
.home-menu-btn { background: var(--bg-card); border: 1px solid #2a2a2a; border-radius: 16px; padding: 20px 10px; display: flex; flex-direction: column; align-items: center; gap: 10px; color: var(--text-light); cursor: pointer; transition: 0.2s; font-size: 0.85rem; }
.home-menu-btn i { font-size: 1.6rem; color: var(--gold); }
.home-menu-btn:active { transform: scale(0.97); background: #1a1a1a; }
.home-info-section { margin: 0 16px 30px; background: var(--bg-card); border: 1px solid #2a2a2a; border-radius: 16px; padding: 18px; }
.home-info-section h3 { color: var(--gold); font-size: 1rem; margin-bottom: 10px; display: flex; align-items: center; gap: 8px; }
.home-info-section p { color: #aaa; font-size: 0.85rem; line-height: 1.6; }
.home-contact-links { display: flex; gap: 10px; margin-top: 14px; }
.contact-btn { flex: 1; padding: 10px; border-radius: 10px; text-align: center; text-decoration: none; font-size: 0.82rem; font-weight: 600; display: flex; align-items: center; justify-content: center; gap: 6px; }
.contact-btn.whatsapp { background: rgba(37,211,102,0.15); color: #25d366; border: 1px solid rgba(37,211,102,0.3); }
.contact-btn.instagram { background: rgba(225,48,108,0.15); color: #e1306c; border: 1px solid rgba(225,48,108,0.3); }

/* --- SERVICES PAGE --- */
.treatment-item { background: var(--bg-card); border: 1px solid #2a2a2a; border-radius: 12px; margin-bottom: 10px; overflow: hidden; }
.treatment-item-header { padding: 16px; display: flex; justify-content: space-between; align-items: center; cursor: pointer; }
.treatment-item-name { display: flex; align-items: center; gap: 10px; color: var(--text-light); font-size: 0.95rem; }
.treatment-item-name i { color: var(--gold); }
.treatment-item-right { display: flex; align-items: center; gap: 10px; }
.treatment-price { color: var(--gold); font-size: 0.85rem; font-weight: 600; }
.chevron-icon { color: #666; font-size: 0.8rem; transition: transform 0.3s; }
.treatment-item-body { padding: 0 16px 16px; border-top: 1px solid #1f1f1f; }
.treatment-item-body p { color: #aaa; font-size: 0.85rem; margin-top: 12px; line-height: 1.6; }
.treatment-item-body p i { color: var(--gold); margin-right: 4px; }
.btn-book-now { margin-top: 14px; width: 100%; background: var(--gold); color: #000; border: none; padding: 12px; border-radius: 10px; font-weight: 700; cursor: pointer; display: flex; align-items: center; justify-content: center; gap: 8px; font-size: 0.9rem; transition: 0.2s; }
.btn-book-now:active { transform: scale(0.98); }

/* --- SHOP PAGE --- */
.products-grid { display: grid; grid-template-columns: 1fr 1fr; gap: 12px; }
.product-card { background: var(--bg-card); border: 1px solid #2a2a2a; border-radius: 14px; overflow: hidden; }
.product-img-wrapper { width: 100%; height: 130px; background: #1a1a1a; overflow: hidden; }
.product-img-wrapper img { width: 100%; height: 100%; object-fit: cover; }
.product-img-placeholder { width: 100%; height: 100%; display: flex; flex-direction: column; align-items: center; justify-content: center; color: #444; gap: 6px; font-size: 1.8rem; }
.product-info { padding: 12px; }
.product-info h3 { font-size: 0.9rem; color: var(--text-light); margin-bottom: 4px; }
.product-desc { font-size: 0.75rem; color: #777; margin-bottom: 6px; line-height: 1.4; }
.product-price { font-size: 0.88rem; color: var(--gold); font-weight: 700; }

/* --- BOOKING PAGE --- */
.booking-card { background: var(--bg-card); border: 1px solid #2a2a2a; border-radius: 12px; padding: 14px; margin-bottom: 10px; display: flex; align-items: center; justify-content: space-between; gap: 10px; }
.booking-card-info { display: flex; flex-direction: column; gap: 3px; }
.booking-card-info strong { color: var(--text-light); font-size: 0.9rem; }
.booking-card-info span { color: #888; font-size: 0.8rem; }
.booking-status { font-size: 0.75rem; font-weight: 600; padding: 4px 10px; border-radius: 20px; border: 1px solid; white-space: nowrap; }
.booking-form-card { background: var(--bg-card); border: 1px solid #2a2a2a; border-radius: 16px; padding: 18px; margin-top: 20px; }
.form-group { margin-bottom: 14px; }
.form-group label { display: block; color: #aaa; font-size: 0.82rem; margin-bottom: 6px; }
.form-group input, .form-group select, .form-group textarea { width: 100%; background: #111; border: 1px solid #2a2a2a; border-radius: 10px; padding: 11px 14px; color: var(--text-light); font-size: 0.88rem; font-family: 'Inter', sans-serif; outline: none; transition: 0.2s; -webkit-appearance: none; }
.form-group input:focus, .form-group select:focus, .form-group textarea:focus { border-color: var(--gold); }
.form-group select option { background: #111; }
.btn-submit { width: 100%; background: var(--gold); color: #000; border: none; padding: 13px; border-radius: 12px; font-weight: 700; font-size: 0.95rem; cursor: pointer; display: flex; align-items: center; justify-content: center; gap: 8px; transition: 0.2s; margin-top: 6px; }
.btn-submit:disabled { opacity: 0.6; cursor: not-allowed; }
.btn-submit:active:not(:disabled) { transform: scale(0.98); }

/* --- GALLERY PAGE --- */
.gallery-grid { display: grid; grid-template-columns: 1fr 1fr 1fr; gap: 8px; }
.gallery-item { aspect-ratio: 1; border-radius: 10px; overflow: hidden; }
.gallery-placeholder { width: 100%; height: 100%; background: var(--bg-card); display: flex; flex-direction: column; align-items: center; justify-content: center; gap: 6px; color: #333; border: 1px solid #1f1f1f; border-radius: 10px; font-size: 1.4rem; }
.gallery-placeholder span { font-size: 0.65rem; color: #444; }
.gallery-note { text-align: center; color: #666; font-size: 0.82rem; margin-top: 16px; padding: 0 20px; }
